import java.io.*;

public class CommandInjectionExample {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a file name to list its contents: ");
        String fileName = reader.readLine();

        // Safe code using ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder("ls", fileName);

        // Redirect error stream to output stream to capture errors
        processBuilder.redirectErrorStream(true);

        Process process = processBuilder.start();

        BufferedReader inputStream = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;

        while ((line = inputStream.readLine()) != null) {
            System.out.println(line);
        }
    }
}

